import { useState, useRef, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';

const QUICK_PROMPTS = [
  'Best careers for a PCM student?',
  'Should I choose CSE or ECE?',
  'How to crack JEE Advanced?',
  'Government jobs after engineering?',
  'Best coding languages to learn in 2025?',
  'Courses after 12th Science?',
];

const SYSTEM_PROMPT = (user) => `You are a friendly, expert AI Career Counselor for Indian students named "Aria". 

Student Profile:
- Name: ${user?.name || 'Student'}
- Stream: ${user?.stream || 'Science (PCM)'}  
- Class 12: ${user?.academics?.p12 || 88}%
- Class 10: ${user?.academics?.p10 || 92}%
- CGPA: ${user?.academics?.cgpa || 8.4}
- Entrance: ${user?.academics?.exam || 'JEE Main'} Score: ${user?.academics?.entrance || 145}/300
- State: ${user?.academics?.state || 'Delhi'}
- Category: ${user?.academics?.category || 'General'}
- Preferred Branch: ${user?.academics?.branch || 'Computer Science'}

Your role: Help with career guidance, college recommendations, course suggestions, government exam prep, study tips, and exam strategy for JEE/BITSAT/VITEEE. 

Rules:
- Be conversational, warm, and encouraging
- Keep responses concise (under 180 words) unless asked for detail
- Use Indian context (Indian colleges, ₹ salaries, Indian exams, CBSE/JEE)
- Use bullet points for lists, but keep prose flowing
- Refer to the student by first name occasionally
- When mentioning salaries, use ₹ LPA format`;

export default function AIChatbot() {
  const { user } = useAuth();
  const [messages, setMessages] = useState([
    {
      role: 'assistant',
      content: `Hi ${user?.name?.split(' ')[0] || 'there'}! 👋 I'm **Aria**, your AI Career Counselor.\n\nI can help you with:\n• Career path recommendations for your profile\n• Best colleges based on your scores\n• Course guidance after 12th\n• Government exam prep (UPSC, SSC, etc.)\n• Study tips & JEE strategy\n\nWhat would you like to explore today?`,
    },
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const bottomRef = useRef(null);

  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [messages, loading]);

  const sendMessage = async (text) => {
    const msg = text || input.trim();
    if (!msg || loading) return;
    setInput('');

    const userMsg = { role: 'user', content: msg };
    const updated = [...messages, userMsg];
    setMessages(updated);
    setLoading(true);

    // Build API message history (exclude initial greeting from history)
    const apiMessages = updated
      .filter((_, i) => i > 0 || updated[0].role !== 'assistant')
      .map(m => ({ role: m.role === 'assistant' ? 'assistant' : 'user', content: m.content }));

    // Ensure first message is from user
    const cleanMessages = apiMessages.filter((m, i) => !(i === 0 && m.role === 'assistant'));

    try {
      const res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          model: 'claude-sonnet-4-20250514',
          max_tokens: 1000,
          system: SYSTEM_PROMPT(user),
          messages: cleanMessages.length > 0 ? cleanMessages : [{ role: 'user', content: msg }],
        }),
      });
      const data = await res.json();
      const reply = data.content?.map(b => b.text || '').join('') || 'Sorry, I had trouble with that. Please try again!';
      setMessages(prev => [...prev, { role: 'assistant', content: reply }]);
    } catch {
      setMessages(prev => [...prev, {
        role: 'assistant',
        content: `⚠️ I'm having trouble connecting right now.\n\nBased on your profile (${user?.academics?.p12 || 88}% in 12th, JEE score ${user?.academics?.entrance || 145}), you're looking at good options in DTU, NSIT, VIT Vellore, and IIIT Hyderabad for CSE. Would you like me to elaborate on any of these when I'm back online?`,
      }]);
    }
    setLoading(false);
  };

  const formatMessage = (text) => {
    return text
      .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
      .replace(/\*(.*?)\*/g, '<em>$1</em>')
      .replace(/•\s/g, '<br/>• ')
      .replace(/\n/g, '<br/>');
  };

  return (
    <div className="page-wrapper animate-in">
      <div className="page-header">
        <div className="page-header-left">
          <h1 className="page-title">🤖 AI Career Counselor</h1>
          <p className="page-subtitle">Powered by Claude AI · Personalized guidance for your academic profile</p>
        </div>
        <button className="btn btn-ghost btn-sm" onClick={() => setMessages([messages[0]])}>
          Clear Chat
        </button>
      </div>

      <div className="card">
        {/* Chat Header */}
        <div className="chat-header">
          <div className="chat-ai-avatar">🤖</div>
          <div>
            <div className="chat-ai-name">Aria — AI Counselor</div>
            <div className="chat-ai-status">Online · Powered by Claude Sonnet</div>
          </div>
          <div style={{ marginLeft: 'auto', display: 'flex', gap: 8 }}>
            <span className="badge badge-success">● Live</span>
            <span className="badge badge-muted">{messages.length - 1} messages</span>
          </div>
        </div>

        {/* Messages */}
        <div className="chat-messages">
          {messages.map((m, i) => (
            <div key={i} className={`chat-msg ${m.role === 'user' ? 'user' : 'ai'}`}>
              <div className={`chat-msg-avatar ${m.role === 'user' ? 'user' : 'ai'}`}>
                {m.role === 'user' ? (user?.initials || 'RS') : '🤖'}
              </div>
              <div className="chat-msg-bubble" dangerouslySetInnerHTML={{ __html: formatMessage(m.content) }} />
            </div>
          ))}
          {loading && (
            <div className="chat-msg ai">
              <div className="chat-msg-avatar ai">🤖</div>
              <div className="chat-msg-bubble">
                <div className="typing-dots"><span /><span /><span /></div>
              </div>
            </div>
          )}
          <div ref={bottomRef} />
        </div>

        {/* Quick prompts */}
        <div className="chat-quick-btns">
          {QUICK_PROMPTS.map(p => (
            <button key={p} className="chat-quick-btn" onClick={() => sendMessage(p)} disabled={loading}>
              {p}
            </button>
          ))}
        </div>

        {/* Input */}
        <div className="chat-input-row">
          <textarea
            className="chat-input"
            rows={2}
            value={input}
            placeholder="Ask about careers, colleges, exams, courses…"
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); sendMessage(); } }}
            disabled={loading}
          />
          <button className="btn btn-success" onClick={() => sendMessage()} disabled={loading || !input.trim()}>
            {loading ? '…' : 'Send ↗'}
          </button>
        </div>
      </div>
    </div>
  );
}
